import React, { useRef, useEffect, useState } from 'react';
import { PRODUCTS, UNIT_PRICES, STATUSES } from '../../utils/constants';

/* ── 195 Countries ─────────────────────────────────────────────────────── */
const COUNTRIES = ["Afghanistan","Albania","Algeria","Andorra","Angola","Antigua and Barbuda","Argentina","Armenia","Australia","Austria","Azerbaijan","Bahamas","Bahrain","Bangladesh","Barbados","Belarus","Belgium","Belize","Benin","Bhutan","Bolivia","Bosnia and Herzegovina","Botswana","Brazil","Brunei","Bulgaria","Burkina Faso","Burundi","Cabo Verde","Cambodia","Cameroon","Canada","Central African Republic","Chad","Chile","China","Colombia","Comoros","Congo (Congo-Brazzaville)","Costa Rica","Croatia","Cuba","Cyprus","Czechia","Denmark","Djibouti","Dominica","Dominican Republic","Ecuador","Egypt","El Salvador","Equatorial Guinea","Eritrea","Estonia","Eswatini","Ethiopia","Fiji","Finland","France","Gabon","Gambia","Georgia","Germany","Ghana","Greece","Grenada","Guatemala","Guinea","Guinea-Bissau","Guyana","Haiti","Honduras","Hungary","Iceland","India","Indonesia","Iran","Iraq","Ireland","Israel","Italy","Jamaica","Japan","Jordan","Kazakhstan","Kenya","Kiribati","Kuwait","Kyrgyzstan","Laos","Latvia","Lebanon","Lesotho","Liberia","Libya","Liechtenstein","Lithuania","Luxembourg","Madagascar","Malawi","Malaysia","Maldives","Mali","Malta","Marshall Islands","Mauritania","Mauritius","Mexico","Micronesia","Moldova","Monaco","Mongolia","Montenegro","Morocco","Mozambique","Myanmar","Namibia","Nauru","Nepal","Netherlands","New Zealand","Nicaragua","Niger","Nigeria","North Korea","North Macedonia","Norway","Oman","Pakistan","Palau","Palestine State","Panama","Papua New Guinea","Paraguay","Peru","Philippines","Poland","Portugal","Qatar","Romania","Russia","Rwanda","Saint Kitts and Nevis","Saint Lucia","Saint Vincent and the Grenadines","Samoa","San Marino","Sao Tome and Principe","Saudi Arabia","Senegal","Serbia","Seychelles","Sierra Leone","Singapore","Slovakia","Slovenia","Solomon Islands","Somalia","South Africa","South Korea","South Sudan","Spain","Sri Lanka","Sudan","Suriname","Sweden","Switzerland","Syria","Tajikistan","Tanzania","Thailand","Timor-Leste","Togo","Tonga","Trinidad and Tobago","Tunisia","Turkey","Turkmenistan","Tuvalu","Uganda","Ukraine","United Arab Emirates","United Kingdom","United States","Uruguay","Uzbekistan","Vanuatu","Vatican City","Venezuela","Vietnam","Yemen","Zambia","Zimbabwe"];

/* ── Spec names ─────────────────────────────────────────────────────────── */
const CREATORS = ['Mr. Michael Harris','Mr. Ryan Cooper','Ms. Olivia Carter','Mr. Lucas Martin'];

/* ── Phone codes ────────────────────────────────────────────────────────── */
const PHONE_CODES = [
  {code:'+91',flag:'🇮🇳',name:'IND'},{code:'+1',flag:'🇺🇸',name:'USA'},
  {code:'+1',flag:'🇨🇦',name:'CAN'},{code:'+44',flag:'🇬🇧',name:'GBR'},
  {code:'+61',flag:'🇦🇺',name:'AUS'},{code:'+64',flag:'🇳🇿',name:'NZL'},
  {code:'+65',flag:'🇸🇬',name:'SGP'},{code:'+852',flag:'🇭🇰',name:'HKG'},
  {code:'+81',flag:'🇯🇵',name:'JPN'},{code:'+82',flag:'🇰🇷',name:'KOR'},
  {code:'+86',flag:'🇨🇳',name:'CHN'},{code:'+49',flag:'🇩🇪',name:'DEU'},
  {code:'+33',flag:'🇫🇷',name:'FRA'},{code:'+39',flag:'🇮🇹',name:'ITA'},
  {code:'+34',flag:'🇪🇸',name:'ESP'},{code:'+31',flag:'🇳🇱',name:'NLD'},
  {code:'+46',flag:'🇸🇪',name:'SWE'},{code:'+47',flag:'🇳🇴',name:'NOR'},
  {code:'+41',flag:'🇨🇭',name:'CHE'},{code:'+43',flag:'🇦🇹',name:'AUT'},
  {code:'+966',flag:'🇸🇦',name:'SAU'},{code:'+971',flag:'🇦🇪',name:'ARE'},
  {code:'+974',flag:'🇶🇦',name:'QAT'},{code:'+973',flag:'🇧🇭',name:'BHR'},
  {code:'+972',flag:'🇮🇱',name:'ISR'},{code:'+20',flag:'🇪🇬',name:'EGY'},
  {code:'+27',flag:'🇿🇦',name:'ZAF'},{code:'+234',flag:'🇳🇬',name:'NGA'},
  {code:'+55',flag:'🇧🇷',name:'BRA'},{code:'+52',flag:'🇲🇽',name:'MEX'},
  {code:'+54',flag:'🇦🇷',name:'ARG'},{code:'+57',flag:'🇨🇴',name:'COL'},
  {code:'+60',flag:'🇲🇾',name:'MYS'},{code:'+62',flag:'🇮🇩',name:'IDN'},
  {code:'+63',flag:'🇵🇭',name:'PHL'},{code:'+66',flag:'🇹🇭',name:'THA'},
  {code:'+84',flag:'🇻🇳',name:'VNM'},{code:'+92',flag:'🇵🇰',name:'PAK'},
  {code:'+880',flag:'🇧🇩',name:'BGD'},{code:'+94',flag:'🇱🇰',name:'LKA'},
  {code:'+977',flag:'🇳🇵',name:'NPL'},{code:'+98',flag:'🇮🇷',name:'IRN'},
];

/* ── Static styles — never recalculated during typing ───────────────────── */
const INPUT_NORMAL = {
  background:'#fff', border:'1.5px solid #cbd5e1', borderRadius:'8px',
  padding:'10px 13px', color:'#1e293b', fontFamily:'inherit',
  fontSize:'13px', width:'100%', outline:'none', boxSizing:'border-box',
};
const INPUT_ERROR = { ...INPUT_NORMAL, border:'1.5px solid #f43f5e' };
const SELECT_ST   = { ...INPUT_NORMAL, cursor:'pointer' };

const onF = e => { e.target.style.borderColor='#6366f1'; e.target.style.boxShadow='0 0 0 3px rgba(99,102,241,.1)'; };
const onB = e => { e.target.style.borderColor='#cbd5e1'; e.target.style.boxShadow='none'; };

/* ── Error message component ─────────────────────────────────────────────── */
function Err({msg}) {
  if (!msg) return null;
  return (
    <span style={{fontSize:'11px',color:'#f43f5e',display:'flex',alignItems:'center',gap:3,marginTop:3,fontWeight:500}}>
      <span style={{fontSize:9}}>●</span>{msg}
    </span>
  );
}

function calcTotal(q,p) {
  return Math.max(1,parseInt(q,10)||1) * Math.max(0,parseFloat(p)||0);
}

export default function OrderModal({ order, onClose, onSave }) {
  const isEdit = !!order;

  /* ── All inputs as uncontrolled refs ────────────────────────────────── */
  const refs = {
    firstName:  useRef(null), lastName:   useRef(null),
    email:      useRef(null), phone:      useRef(null),
    street:     useRef(null), city:       useRef(null),
    stateVal:   useRef(null), postalCode: useRef(null),
    country:    useRef(null), product:    useRef(null),
    status:     useRef(null), createdBy:  useRef(null),
    orderDate:  useRef(null),
  };

  /* ── Only non-input state ───────────────────────────────────────────── */
  const [errs,         setErrs]         = useState({});
  const [qty,          setQty]          = useState(1);
  const [unitPriceVal, setUnitPriceVal] = useState(2999);
  const [dialCode,     setDialCode]     = useState('+91');
  const [saving,       setSaving]       = useState(false);

  /* ── Populate on edit ───────────────────────────────────────────────── */
  useEffect(() => {
    const s = order || {};
    const set = (ref, val) => { if (ref?.current) ref.current.value = val ?? ''; };
    set(refs.firstName,  s.firstName  || '');
    set(refs.lastName,   s.lastName   || '');
    set(refs.email,      s.email      || '');
    if (s.phone) {
      const m = PHONE_CODES.find(p => s.phone.startsWith(p.code+' '));
      if (m) { setDialCode(m.code); set(refs.phone, s.phone.replace(m.code+' ','')); }
      else   { set(refs.phone, s.phone); }
    }
    set(refs.street,    s.street    || '');
    set(refs.city,      s.city      || '');
    set(refs.stateVal,  s.state     || '');
    set(refs.postalCode,s.postalCode|| '');
    set(refs.country,   s.country   || 'United States');
    set(refs.product,   s.product   || 'Fiber Internet 300 Mbps');
    setQty(s.quantity  || 1);
    setUnitPriceVal(s.unitPrice || UNIT_PRICES['Fiber Internet 300 Mbps']);
    set(refs.status,    s.status    || 'Pending');
    set(refs.createdBy, s.createdBy || 'Mr. Michael Harris');
    set(refs.orderDate, s.orderDate ? String(s.orderDate).slice(0,10) : new Date().toISOString().slice(0,10));
  }, []); // eslint-disable-line

  /* ── Validation — runs on submit only, clears on change ────────────── */
  function validate() {
    const r = refs;
    const e = {};
    if (!r.firstName.current?.value?.trim())  e.firstName  = 'Please fill the field';
    if (!r.lastName.current?.value?.trim())   e.lastName   = 'Please fill the field';
    const email = r.email.current?.value || '';
    if (!email.trim())                         e.email      = 'Please fill the field';
    else if (!/^[^@]+@[^@]+\.[^@]{2,}$/.test(email)) e.email = 'Enter a valid email';
    const phone = r.phone.current?.value || '';
    if (!phone.trim())                         e.phone      = 'Please fill the field';
    if (!r.street.current?.value?.trim())     e.street     = 'Please fill the field';
    if (!r.city.current?.value?.trim())       e.city       = 'Please fill the field';
    if (!r.stateVal.current?.value?.trim())   e.stateVal   = 'Please fill the field';
    if (!r.postalCode.current?.value?.trim()) e.postalCode = 'Please fill the field';
    if (qty < 1)                               e.qty        = 'Min 1';
    return e;
  }

  async function submit(e) {
    e.preventDefault();
    const ev = validate();
    if (Object.keys(ev).length) { setErrs(ev); return; }
    setSaving(true);
    try {
      const r = refs;
      await onSave({
        firstName:   r.firstName.current?.value  || '',
        lastName:    r.lastName.current?.value   || '',
        email:       r.email.current?.value      || '',
        phone:       (dialCode+' '+(r.phone.current?.value||'')).trim(),
        street:      r.street.current?.value     || '',
        city:        r.city.current?.value       || '',
        state:       r.stateVal.current?.value   || '',
        postalCode:  r.postalCode.current?.value || '',
        country:     r.country.current?.value    || 'United States',
        product:     r.product.current?.value    || '',
        quantity:    qty,
        unitPrice:   unitPriceVal,
        totalAmount: calcTotal(qty, unitPriceVal),
        status:      r.status.current?.value     || 'Pending',
        createdBy:   r.createdBy.current?.value  || '',
        orderDate:   r.orderDate.current?.value  || '',
      });
      onClose();
    } catch(err) { setErrs({_:err.message}); }
    finally { setSaving(false); }
  }

  /* ── Clear error when user starts typing ───────────────────────────── */
  const clr = key => () => { if (errs[key]) setErrs(p => ({...p,[key]:''})); };

  /* ── Field label + error wrapper ────────────────────────────────────── */
  const F = ({name,label,full,children}) => (
    <div style={full?{gridColumn:'1/-1'}:{}}>
      <label style={{display:'block',fontSize:'11px',fontWeight:600,color:'#64748b',marginBottom:5,letterSpacing:'.02em',textTransform:'uppercase'}}>
        {label} <span style={{color:'#f43f5e'}}>*</span>
      </label>
      {children}
      <Err msg={errs[name]}/>
    </div>
  );

  return (
    <div className="overlay" onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="modal modal-xl" onClick={e=>e.stopPropagation()}>

        <div style={{height:3,background:'linear-gradient(90deg,#10b981,#06b6d4,#6366f1)',borderRadius:'var(--r3) var(--r3) 0 0'}}/>

        <div className="modal-hd">
          <div>
            <h2>{isEdit?'Edit Order':'Create Order'}</h2>
            <p style={{fontSize:12,color:'var(--t3)',marginTop:3}}>All fields marked * are mandatory</p>
          </div>
          <button className="btn-icon" type="button" onClick={onClose}>✕</button>
        </div>

        <form onSubmit={submit}>
          <div className="modal-body">

            {errs._ && (
              <div style={{background:'#fef2f2',border:'1px solid #fecaca',borderRadius:'8px',padding:'10px 14px',color:'#f43f5e',fontSize:13}}>
                {errs._}
              </div>
            )}

            {/* ══ CUSTOMER INFORMATION ══ */}
            <div>
              <div className="section-title">Customer Information</div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14}}>

                <F name="firstName" label="First Name">
                  <input ref={refs.firstName} type="text" placeholder="First name"
                    defaultValue="" autoComplete="given-name"
                    style={errs.firstName ? INPUT_ERROR : INPUT_NORMAL}
                    onFocus={onF} onBlur={onB} onChange={clr('firstName')}/>
                </F>

                <F name="lastName" label="Last Name">
                  <input ref={refs.lastName} type="text" placeholder="Last name"
                    defaultValue="" autoComplete="family-name"
                    style={errs.lastName ? INPUT_ERROR : INPUT_NORMAL}
                    onFocus={onF} onBlur={onB} onChange={clr('lastName')}/>
                </F>

                <F name="email" label="Email ID">
                  <input ref={refs.email} type="text" placeholder="email@example.com"
                    defaultValue="" autoComplete="email"
                    style={errs.email ? INPUT_ERROR : INPUT_NORMAL}
                    onFocus={onF} onBlur={onB} onChange={clr('email')}/>
                </F>

                <F name="phone" label="Phone Number">
                  <div style={{
                    display:'flex',border:`1.5px solid ${errs.phone?'#f43f5e':'#cbd5e1'}`,
                    borderRadius:'8px',overflow:'hidden',background:'#fff',
                  }}
                    onFocusCapture={e=>{e.currentTarget.style.borderColor='#6366f1';e.currentTarget.style.boxShadow='0 0 0 3px rgba(99,102,241,.1)';}}
                    onBlurCapture={e=>{e.currentTarget.style.borderColor='#cbd5e1';e.currentTarget.style.boxShadow='none';}}>
                    <select value={dialCode} onChange={e=>setDialCode(e.target.value)}
                      style={{border:'none',outline:'none',background:'#f8fafc',borderRight:'1px solid #e2e8f0',padding:'10px 8px',fontFamily:'inherit',fontSize:'13px',color:'#1e293b',cursor:'pointer',flexShrink:0,minWidth:92,fontWeight:600}}>
                      {PHONE_CODES.map((p,i)=><option key={i} value={p.code}>{p.flag} {p.code} {p.name}</option>)}
                    </select>
                    <input ref={refs.phone} type="tel" placeholder="9876543210"
                      defaultValue="" autoComplete="tel-national"
                      style={{flex:1,border:'none',outline:'none',padding:'10px 13px',fontFamily:'inherit',fontSize:'13px',color:'#1e293b',background:'transparent',minWidth:0}}
                      onChange={clr('phone')}/>
                  </div>
                  <Err msg={errs.phone}/>
                </F>

                <F name="street" label="Street Address" full>
                  <input ref={refs.street} type="text" placeholder="123 Main Street, Area"
                    defaultValue="" autoComplete="street-address"
                    style={errs.street ? INPUT_ERROR : INPUT_NORMAL}
                    onFocus={onF} onBlur={onB} onChange={clr('street')}/>
                </F>

                <F name="city" label="City">
                  <input ref={refs.city} type="text" placeholder="City"
                    defaultValue="" style={errs.city ? INPUT_ERROR : INPUT_NORMAL}
                    onFocus={onF} onBlur={onB} onChange={clr('city')}/>
                </F>

                <F name="stateVal" label="State / Province">
                  <input ref={refs.stateVal} type="text" placeholder="State"
                    defaultValue="" style={errs.stateVal ? INPUT_ERROR : INPUT_NORMAL}
                    onFocus={onF} onBlur={onB} onChange={clr('stateVal')}/>
                </F>

                <F name="postalCode" label="Postal Code">
                  <input ref={refs.postalCode} type="text" placeholder="600001"
                    defaultValue="" style={errs.postalCode ? INPUT_ERROR : INPUT_NORMAL}
                    onFocus={onF} onBlur={onB} onChange={clr('postalCode')}/>
                </F>

                <F name="country" label="Country">
                  <select ref={refs.country} defaultValue="United States"
                    style={SELECT_ST} onFocus={onF} onBlur={onB}>
                    {COUNTRIES.map(c=><option key={c} value={c}>{c}</option>)}
                  </select>
                </F>

              </div>
            </div>

            {/* ══ ORDER INFORMATION ══ */}
            <div>
              <div className="section-title">Order Information</div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14}}>

                <F name="product" label="Choose Product" full>
                  <select ref={refs.product} defaultValue="Fiber Internet 300 Mbps"
                    style={SELECT_ST} onFocus={onF} onBlur={onB}
                    onChange={e=>{
                      const price = UNIT_PRICES[e.target.value]||0;
                      setUnitPriceVal(price);
                    }}>
                    {PRODUCTS.map(p=><option key={p} value={p}>{p}</option>)}
                  </select>
                </F>

                <F name="qty" label="Quantity">
                  <div style={{display:'flex',alignItems:'center',border:'1.5px solid #cbd5e1',borderRadius:'8px',overflow:'hidden',background:'#fff',height:41}}>
                    <button type="button" onClick={()=>setQty(q=>Math.max(1,q-1))}
                      style={{width:44,height:'100%',background:'#f8fafc',border:'none',borderRight:'1px solid #e2e8f0',cursor:'pointer',fontSize:18,fontWeight:600,color:'#1e293b',flexShrink:0,userSelect:'none'}}
                      onMouseEnter={e=>e.currentTarget.style.background='#e2e8f0'}
                      onMouseLeave={e=>e.currentTarget.style.background='#f8fafc'}>−</button>
                    <input type="number" min="1" value={qty}
                      onChange={e=>setQty(Math.max(1,parseInt(e.target.value,10)||1))}
                      style={{flex:1,border:'none',outline:'none',textAlign:'center',fontWeight:800,fontSize:'16px',fontFamily:'inherit',color:'#1e293b',background:'transparent',padding:'0 4px'}}/>
                    <button type="button" onClick={()=>setQty(q=>q+1)}
                      style={{width:44,height:'100%',background:'#f8fafc',border:'none',borderLeft:'1px solid #e2e8f0',cursor:'pointer',fontSize:18,fontWeight:600,color:'#1e293b',flexShrink:0,userSelect:'none'}}
                      onMouseEnter={e=>e.currentTarget.style.background='#e2e8f0'}
                      onMouseLeave={e=>e.currentTarget.style.background='#f8fafc'}>+</button>
                  </div>
                </F>

                <F name="unitPrice" label="Unit Price ($)">
                  <div style={{position:'relative'}}>
                    <span style={{position:'absolute',left:12,top:'50%',transform:'translateY(-50%)',color:'#94a3b8',fontSize:13,fontWeight:600,pointerEvents:'none'}}>$</span>
                    <input type="number" min="0" step="1" value={unitPriceVal}
                      onChange={e=>setUnitPriceVal(Math.max(0,parseFloat(e.target.value)||0))}
                      onFocus={onF} onBlur={onB}
                      style={{...INPUT_NORMAL,paddingLeft:26,fontSize:14,fontWeight:600}}/>
                  </div>
                </F>

                <F name="totalAmount" label="Total Amount (Read Only)">
                  <div style={{background:'#f0fdf4',border:'1.5px solid #86efac',borderRadius:'8px',padding:'10px 16px',display:'flex',alignItems:'center',gap:6}}>
                    <span style={{fontSize:15,color:'#10b981',fontWeight:600}}>$</span>
                    <span style={{fontSize:18,fontWeight:800,fontFamily:'var(--ff-h)',color:'#10b981',letterSpacing:'-0.02em'}}>
                      {(qty*unitPriceVal).toLocaleString('en-US',{minimumFractionDigits:2})}
                    </span>
                    <span style={{fontSize:11,color:'#86efac',marginLeft:4}}>{qty} × ${unitPriceVal.toLocaleString('en-US')}</span>
                  </div>
                </F>

                <F name="status" label="Status">
                  <select ref={refs.status} defaultValue="Pending"
                    style={SELECT_ST} onFocus={onF} onBlur={onB}>
                    {STATUSES.map(s=><option key={s} value={s}>{s}</option>)}
                  </select>
                </F>

                <F name="createdBy" label="Created By">
                  <select ref={refs.createdBy} defaultValue="Mr. Michael Harris"
                    style={SELECT_ST} onFocus={onF} onBlur={onB}>
                    {CREATORS.map(c=><option key={c} value={c}>{c}</option>)}
                  </select>
                </F>

              </div>
            </div>

          </div>

          <div className="modal-ft">
            <button className="btn btn-ghost" type="button" onClick={onClose}>Cancel</button>
            <button className="btn btn-primary" type="submit" disabled={saving}
              style={{minWidth:130,justifyContent:'center'}}>
              {saving?<><span className="spinner"/>Saving…</>:isEdit?'Update Order':'Create Order'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
